// createSecureHTTPClient creates an HTTP client with SSRF protection
func createSecureHTTPClient() *http.Client {
	// Create a custom dialer that validates IPs at connection time
	dialer := &net.Dialer{
		Timeout:   10 * time.Second,
		KeepAlive: 30 * time.Second,
	}

	secureDialContext := func(ctx context.Context, network, addr string) (net.Conn, error) {
		// Resolve the address
		host, port, err := net.SplitHostPort(addr)
		if err != nil {
			return nil, err
		}

		// Resolve hostname to IP
		ips, err := net.DefaultResolver.LookupIPAddr(ctx, host)
		if err != nil {
			return nil, err
		}

		// Check all resolved IPs for private/internal addresses
		for _, ipAddr := range ips {
			if isPrivateIP(ipAddr.IP) {
