			}
		}

		// Use the first resolved IP for connection
		return dialer.DialContext(ctx, network, net.JoinHostPort(ips[0].IP.String(), port))
	}

	return &http.Client{
		Timeout: 10 * time.Second,
		Transport: &http.Transport{
