package main

import (
	"net/http"
	"net/url"
	"time"

	"github.com/gofiber/fiber/v2"
)

// WebhookConfig represents the webhook configuration request body
type WebhookConfig struct {
	WebhookURL string `json:"webhook_url"`
}

// WebhookResponse represents the response from the webhook configuration
type WebhookResponse struct {
	Success bool   `json:"success"`
	Message string `json:"message"`
}

// ConfigureWebhook handles webhook configuration requests
func ConfigureWebhook(ctx *fiber.Ctx) error {
	var config WebhookConfig

	// Parse JSON body
	if err := ctx.BodyParser(&config); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(WebhookResponse{
			Success: false,
			Message: "Invalid JSON body",
		})
	}

	// Validate webhook_url is not empty
	if config.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(WebhookResponse{
			Success: false,
			Message: "webhook_url is required",
		})
	}

	// Validate URL format
	if _, err := url.ParseRequestURI(config.WebhookURL); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(WebhookResponse{
			Success: false,
			Message: "Invalid URL format",
		})
	}

	// Create HTTP client with 3 second timeout
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	// Send test GET request to validate webhook URL
	resp, err := client.Get(config.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(WebhookResponse{
			Success: false,
			Message: "Failed to validate webhook URL: " + err.Error(),
		})
	}
	defer resp.Body.Close()

	// Save configuration (in a real application, this would persist to database)
	// For this example, configuration is considered saved after successful validation

	return ctx.Status(fiber.StatusOK).JSON(WebhookResponse{
		Success: true,
		Message: "Webhook configured successfully",
	})
}

func main() {
	app := fiber.New()

	// Register the webhook configuration endpoint
	app.Post("/configure-webhook", ConfigureWebhook)

	// Start the server
	if err := app.Listen(":3000"); err != nil {
		panic(err)
	}
}

