// validateWebhookURL checks if the URL is safe to use (prevents SSRF)
func validateWebhookURL(parsedURL *url.URL) error {
	host := parsedURL.Hostname()

	// Block localhost variations
	if isLocalhost(host) {
		return fmt.Errorf("localhost addresses are not allowed")
	}

