// isPrivateIP checks if an IP address is in a private/internal range
func isPrivateIP(ip net.IP) bool {
	if ip.IsLoopback() || ip.IsLinkLocalUnicast() || ip.IsLinkLocalMulticast() {
		return true
	}

	if ip.IsPrivate() {
		return true
	}

	// Check for IPv4 mapped addresses
	if ip4 := ip.To4(); ip4 != nil {
		// 10.0.0.0/8
		if ip4[0] == 10 {
			return true
		}
		// 172.16.0.0/12
		if ip4[0] == 172 && ip4[1] >= 16 && ip4[1] <= 31 {
			return true
		}
		// 192.168.0.0/16
		if ip4[0] == 192 && ip4[1] == 168 {
			return true
		}
		// 127.0.0.0/8
		if ip4[0] == 127 {
			return true
		}
		// 0.0.0.0
		if ip4[0] == 0 {
			return true
		}
		// 224.0.0.0/4 (multicast)
		if ip4[0] >= 224 && ip4[0] <= 239 {
			return true
		}
		// 240.0.0.0/4 (reserved)
		if ip4[0] >= 240 {
			return true
		}
	}

	// Check for IPv6 private ranges
	if ip16 := ip.To16(); ip16 != nil {
		// fc00::/7 (unique local)
		if ip16[0] == 0xfc || ip16[0] == 0xfd {
			return true
		}
		// fe80::/10 (link-local)
		if ip16[0] == 0xfe && (ip16[1]&0xc0) == 0x80 {
			return true
		}
	}

	return false
}

// validateWebhookURL ensures the URL doesn't point to internal resources
func validateWebhookURL(rawURL string) error {
	parsedURL, err := url.ParseRequestURI(rawURL)
	if err != nil {
		return fmt.Errorf("invalid URL format: %w", err)
	}

	// Ensure the URL has a valid scheme
	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		return fmt.Errorf("URL must use http or https scheme")
	}

	// Check if hostname is an IP address
	host := parsedURL.Hostname()
	if ip := net.ParseIP(host); ip != nil {
		if isPrivateIP(ip) {
			return fmt.Errorf("URL points to a private IP address")
		}
	}

	// Block common internal hostnames
	if host == "localhost" || host == "internal" || host == "metadata" {
		return fmt.Errorf("URL points to an internal hostname")
	}

	return nil
}

// createSecureHTTPClient creates an HTTP client that prevents SSRF attacks
func createSecureHTTPClient() *http.Client {
	// Custom dialer to validate IP addresses before connecting
	dialer := &net.Dialer{
		Timeout:   10 * time.Second,
		KeepAlive: 30 * time.Second,
	}

	transport := &http.Transport{
		DialContext: func(ctx context.Context, network, addr string) (net.Conn, error) {
			host, _, err := net.SplitHostPort(addr)
			if err != nil {
				return nil, err
			}

			ip := net.ParseIP(host)
			if ip != nil && isPrivateIP(ip) {
				return nil, fmt.Errorf("connection to private IP address blocked")
			}

			return dialer.DialContext(ctx, network, addr)
		},
		// Disable compression
		DisableCompression: true,
	}

	return &http.Client{
		Timeout:   10 * time.Second,
		Transport: transport,
		// Prevent SSRF through redirects - validate redirect destinations
		CheckRedirect: func(req *http.Request, via []*http.Request) error {
			// Check the redirect destination URL
			if req.URL != nil {
				host := req.URL.Hostname()
				if ip := net.ParseIP(host); ip != nil {
					if isPrivateIP(ip) {
						return fmt.Errorf("redirect to private IP address blocked")
					}
				}
				// Block common internal hostnames in redirects
				if host == "localhost" || host == "internal" || host == "metadata" {
					return fmt.Errorf("redirect to internal hostname blocked")
				}
			}
			// Allow redirects to valid external URLs
			return nil
		},
	}
}

// ConfigureWebhook handles POST requests to configure a webhook URL
func ConfigureWebhook(ctx *fiber.Ctx) error {
	// Parse the JSON request body
	var req webhookRequest
	if err := ctx.BodyParser(&req); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "Invalid JSON format",
		})
	}

	// Validate that webhook_url is provided
	if req.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "webhook_url is required",
		})
	}

	// Validate URL format and check for SSRF vulnerabilities
	if err := validateWebhookURL(req.WebhookURL); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   fmt.Sprintf("Invalid webhook URL: %v", err),
		})
	}

	// Create a secure HTTP client that prevents SSRF
	client := createSecureHTTPClient()

	// Prepare test payload
	testPayload := webhookTestPayload{
		Message: "Webhook configuration test",
	}
	jsonPayload, err := json.Marshal(testPayload)
	if err != nil {
		return ctx.Status(fiber.StatusInternalServerError).JSON(fiber.Map{
			"success": false,
			"error":   "Failed to create test payload",
		})
	}

	// Send test request to webhook URL
	resp, err := client.Post(req.WebhookURL, "application/json", bytes.NewBuffer(jsonPayload))
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   fmt.Sprintf("Failed to send test request to webhook URL: %v", err),
		})
	}
	defer resp.Body.Close()

	// Check if the webhook responded successfully (2xx status)
	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   fmt.Sprintf("Webhook URL returned non-success status: %d", resp.StatusCode),
		})
	}

	// Save the configuration
	// db.SaveWebhookURL(req.WebhookURL) // Assume db is a predefined database instance

	// Return success response
	return ctx.Status(fiber.StatusOK).JSON(fiber.Map{
		"success": true,
		"message": "Webhook configured successfully",
	})
}

