// isPrivateIP checks if an IP address is private/internal or potentially dangerous
func isPrivateIP(ip net.IP) bool {
	// Check for loopback addresses
	if ip.IsLoopback() {
		return true
	}

	// Check for private IP ranges
	if ip.IsPrivate() {
		return true
	}

	// Check for link-local unicast addresses
	if ip.IsLinkLocalUnicast() {
		return true
	}

	// Check for link-local multicast addresses
	if ip.IsLinkLocalMulticast() {
		return true
	}

	// Check for cloud metadata service IPs (common SSRF targets)
	// AWS, GCP, Azure metadata service
	if ip.Equal(net.IPv4(169, 254, 169, 254)) {
		return true
	}

	return false
}

// validateWebhookURL validates that the webhook URL doesn't point to internal resources
func validateWebhookURL(rawURL string) error {
	parsedURL, err := url.Parse(rawURL)
	if err != nil {
		return fmt.Errorf("invalid URL format: %v", err)
	}

	// Check scheme
	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		return fmt.Errorf("URL must use http or https scheme")
	}

	// Check hostname
	host := parsedURL.Hostname()
	if host == "" {
		return fmt.Errorf("URL must have a hostname")
	}

	// Check for localhost variations
	if host == "localhost" {
		return fmt.Errorf("localhost is not allowed")
	}

	// Try to parse as IP address first
	if ip := net.ParseIP(host); ip != nil {
		if isPrivateIP(ip) {
			return fmt.Errorf("URL points to private/internal IP address")
		}
		return nil
	}

	// Resolve the hostname to check IP addresses
	ips, err := net.LookupIP(host)
	if err != nil {
		return fmt.Errorf("failed to resolve hostname: %v", err)
	}

	// Check all resolved IPs
	for _, ip := range ips {
		if isPrivateIP(ip) {
			return fmt.Errorf("URL points to private/internal IP address")
		}
	}

	return nil
}

// createSecureHTTPClient creates an HTTP client with SSRF protections
func createSecureHTTPClient(timeout time.Duration) *http.Client {
	// Custom dialer to validate IP addresses before connecting
	dialer := &net.Dialer{
		Timeout:   timeout,
		KeepAlive: 30 * time.Second,
	}

	// Custom dial context that validates the resolved IP
	dialContext := func(ctx context.Context, network, addr string) (net.Conn, error) {
		host, _, err := net.SplitHostPort(addr)
		if err != nil {
			return nil, err
		}

		// Parse the IP address
		ip := net.ParseIP(host)
		if ip != nil && isPrivateIP(ip) {
			return nil, fmt.Errorf("connection to private IP address blocked")
		}

		return dialer.DialContext(ctx, network, addr)
	}

	return &http.Client{
		Timeout: timeout,
		Transport: &http.Transport{
			DialContext:           dialContext,
			DisableCompression:    false,
			MaxIdleConns:          100,
