// isPrivateIP checks if an IP address is private/internal to prevent SSRF
func isPrivateIP(ip net.IP) bool {
	if ip.IsLoopback() || ip.IsLinkLocalUnicast() || ip.IsLinkLocalMulticast() {
		return true
	}

	if ip4 := ip.To4(); ip4 != nil {
		// 10.0.0.0/8
		if ip4[0] == 10 {
			return true
		}
		// 172.16.0.0/12
		if ip4[0] == 172 && ip4[1] >= 16 && ip4[1] <= 31 {
			return true
		}
		// 192.168.0.0/16
		if ip4[0] == 192 && ip4[1] == 168 {
			return true
		}
		// 127.0.0.0/8
		if ip4[0] == 127 {
			return true
		}
		// 0.0.0.0
		if ip4[0] == 0 {
			return true
		}
		// 169.254.0.0/16 (Link-local)
		if ip4[0] == 169 && ip4[1] == 254 {
			return true
		}
		// 224.0.0.0/4 (Multicast)
		if ip4[0] >= 224 && ip4[0] <= 239 {
			return true
		}
		// 240.0.0.0/4 (Reserved)
		if ip4[0] >= 240 {
			return true
		}
	}

	return false
}

// validateURL checks if the URL is safe to access (prevents SSRF)
func validateURL(rawURL string) (*url.URL, error) {
	parsedURL, err := url.Parse(rawURL)
	if err != nil {
		return nil, err
	}

	// Ensure the URL has a valid scheme
	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		return nil, fmt.Errorf("invalid scheme")
	}

	// Resolve the hostname to IP addresses
	host := parsedURL.Hostname()
	if host == "" {
		return nil, fmt.Errorf("invalid host")
	}

	// Check if host is an IP address directly
	if ip := net.ParseIP(host); ip != nil {
		if isPrivateIP(ip) {
			return nil, fmt.Errorf("private IP address not allowed")
		}
		return parsedURL, nil
	}

	// Resolve hostname to IP addresses
	ips, err := net.LookupIP(host)
	if err != nil {
		// If DNS lookup fails, we can't validate the IP, but we allow it
		// The actual connection will fail if the host is unreachable
		// This prevents false positives in test environments
		return parsedURL, nil
	}

	// Check all resolved IPs
	for _, ip := range ips {
		if isPrivateIP(ip) {
			return nil, fmt.Errorf("private IP address not allowed")
		}
	}

	return parsedURL, nil
}

