		Transport: &http.Transport{
			DialContext: func(dialer *net.Dialer) func(net.Context, string, string) (net.Conn, error) {
				return func(ctx net.Context, network, addr string) (net.Conn, error) {
					conn, err := dialer.DialContext(ctx, network, addr)
					if err != nil {
