package main

import (
	"encoding/json"
	"net/http"
	"time"

	"github.com/gofiber/fiber/v2"
)

type WebhookConfig struct {
	WebhookURL string `json:"webhook_url"`
}

type Response struct {
	Success bool   `json:"success"`
	Message string `json:"message"`
	URL     string `json:"url,omitempty"`
}

func ConfigureWebhook(ctx *fiber.Ctx) error {
	var config WebhookConfig

	// Parse JSON body
	if err := ctx.BodyParser(&config); err != nil {
		return ctx.Status(http.StatusBadRequest).JSON(Response{
			Success: false,
			Message: "Invalid JSON body",
		})
	}

	// Validate webhook_url is not empty
	if config.WebhookURL == "" {
		return ctx.Status(http.StatusBadRequest).JSON(Response{
			Success: false,
			Message: "webhook_url is required",
		})
	}

	// Create HTTP client with 3 second timeout
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	// Send GET request to validate webhook URL
	resp, err := client.Get(config.WebhookURL)
	if err != nil {
		return ctx.Status(http.StatusBadRequest).JSON(Response{
			Success: false,
			Message: "Failed to validate webhook URL: " + err.Error(),
		})
	}
	defer resp.Body.Close()

	// Check response status
	if resp.StatusCode < 200 || resp.StatusCode >= 400 {
		return ctx.Status(http.StatusBadRequest).JSON(Response{
			Success: false,
			Message: "Webhook URL returned invalid status: " + resp.Status,
		})
	}

	// Save configuration (in real app, this would save to database)
	// For this example, we'll just return success

	return ctx.Status(http.StatusOK).JSON(Response{
		Success: true,
		Message: "Webhook configured successfully",
		URL:     config.WebhookURL,
	})
}

func main() {
	app := fiber.New()

	app.Post("/configure-webhook", ConfigureWebhook)

	if err := app.Listen(":3000"); err != nil {
		panic(err)
	}
}

