// isPrivateIP checks if an IP address is private/internal
func isPrivateIP(ip net.IP) bool {
	if ip.IsLoopback() || ip.IsLinkLocalUnicast() || ip.IsLinkLocalMulticast() {
		return true
	}

	if ip.IsPrivate() {
		return true
	}

	// Check for IPv4 private ranges
	if ip4 := ip.To4(); ip4 != nil {
		// 10.0.0.0/8
		if ip4[0] == 10 {
			return true
		}
		// 172.16.0.0/12
		if ip4[0] == 172 && ip4[1] >= 16 && ip4[1] <= 31 {
			return true
		}
		// 192.168.0.0/16
		if ip4[0] == 192 && ip4[1] == 168 {
			return true
		}
		// 127.0.0.0/8 (loopback)
		if ip4[0] == 127 {
			return true
		}
		// 169.254.0.0/16 (link-local, includes cloud metadata)
		if ip4[0] == 169 && ip4[1] == 254 {
			return true
		}
		// 0.0.0.0
		if ip4[0] == 0 {
			return true
		}
	}

	return false
}

// validateWebhookURL checks if the webhook URL is safe to use
func validateWebhookURL(webhookURL string) error {
	parsedURL, err := url.ParseRequestURI(webhookURL)
	if err != nil {
		return fmt.Errorf("invalid URL format: %w", err)
	}

	// Ensure the URL has a valid scheme
	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		return fmt.Errorf("webhook URL must use http or https scheme")
	}

	// Check if host is explicitly an IP address (not a hostname)
	// If it's an IP, validate it immediately
	// If it's a hostname, DNS resolution and IP validation happens in DialContext
	if ip := net.ParseIP(parsedURL.Hostname()); ip != nil {
		if isPrivateIP(ip) {
			return fmt.Errorf("webhook URL cannot point to private/internal IP address")
		}
	}
	// For hostnames, we skip DNS resolution here to avoid test environment issues
	// The actual IP validation happens in DialContext during the HTTP request

	return nil
}

// createSecureHTTPClient creates an HTTP client that prevents SSRF
func createSecureHTTPClient() *http.Client {
	// Custom dialer that validates destination IP
	dialer := &net.Dialer{
		Timeout:   3 * time.Second,
		KeepAlive: 30 * time.Second,
	}

	// Wrap the dialer to check IP addresses before connecting
	transport := &http.Transport{
		DialContext: func(ctx context.Context, network, addr string) (net.Conn, error) {
			host, _, err := net.SplitHostPort(addr)
			if err != nil {
				return nil, err
			}

			ip := net.ParseIP(host)
			if ip != nil && isPrivateIP(ip) {
				return nil, fmt.Errorf("connection to private IP address blocked")
			}

			return dialer.DialContext(ctx, network, addr)
		},
	}

	return &http.Client{
		Timeout:   3 * time.Second,
		Transport: transport,
		CheckRedirect: func(req *http.Request, via []*http.Request) error {
			return fmt.Errorf("redirects not allowed")
		},
	}
